const BASE_URL = "https://9anime.me.uk";

export async function search(query) {
  const res = await fetch(`${BASE_URL}/?s=${encodeURIComponent(query)}`);
  const html = await res.text();

  const results = [];
  const items = html.match(/<a href="https:\/\/9anime\.me\.uk\/[^\"]+" title="[^\"]+"/g) || [];

  for (const item of items) {
    const url = item.match(/href="([^\"]+)"/)?.[1];
    const title = item.match(/title="([^\"]+)"/)?.[1];

    if (url && title) results.push({ title, url });
  }

  return results.slice(0, 20);
}

export async function getEpisodes(animeUrl) {
  const res = await fetch(animeUrl);
  const html = await res.text();

  const episodes = [];
  const matches = html.match(/href="https:\/\/9anime\.me\.uk\/[^\"]*episode[^\"]*"/g) || [];

  let count = 1;
  for (const m of matches) {
    const url = m.match(/href="([^\"]+)"/)?.[1];
    if (url) episodes.push({ title: `Episode ${count++}`, url });
  }

  return episodes;
}

export async function getVideo(episodeUrl) {
  const res = await fetch(episodeUrl);
  const html = await res.text();

  const iframe = html.match(/<iframe[^>]+src="([^\"]+)"/)?.[1];
  if (iframe) return { url: iframe };

  const source = html.match(/source src="([^\"]+)"/)?.[1];
  return { url: source || null };
}
